import{_ as r,a,b as n,c as t,d as i,e as s,f as o}from"./chunks/vbv_gruppe_logo.C15vlyRa.js";import{_ as l,o as d,c,an as u}from"./chunks/framework.D5fFzH9V.js";const y=JSON.parse('{"title":"Hallo! Wir sind die Syslifters.","description":"Syslifters ist ein Pentesting-Unternehmen mit Fokus auf Active Directory/Entra ID und Webanwendungen, inkl. Referenzen, Stärken und Kontakt.","frontmatter":{"title":"Hallo! Wir sind die Syslifters.","description":"Syslifters ist ein Pentesting-Unternehmen mit Fokus auf Active Directory/Entra ID und Webanwendungen, inkl. Referenzen, Stärken und Kontakt."},"headers":[],"relativePath":"de/index.md","filePath":"de/index.md"}'),h={name:"de/index.md"};function m(p,e,f,g,k,_){return d(),c("div",null,[...e[0]||(e[0]=[u('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /de.md for this page in Markdown format</div><h1 id="hallo-wir-sind-die-syslifters" tabindex="-1">Hallo! Wir sind die Syslifters. <a class="header-anchor" href="#hallo-wir-sind-die-syslifters" aria-label="Permalink to &quot;Hallo! Wir sind die Syslifters.&quot;">​</a></h1><p>Wir sind ein junges Security-Unternehmen mit Fokus auf Pentests. Unsere Spezialisierungen sind interne Firmennetzwerke (Active Directory-/Entra-ID-Infrastrukturen) und Web-Applikationen.</p><p>Mit unserem klaren Fokus haben wir das größtmögliche Know-How im Bereich der offensiven IT-Security.</p><h2 id="referenzen-und-partner" tabindex="-1">Referenzen und Partner <a class="header-anchor" href="#referenzen-und-partner" aria-label="Permalink to &quot;Referenzen und Partner&quot;">​</a></h2><div class="partner-grid"><a class="partner-card" href="https://it-tuv.com/" target="_blank" rel="noreferrer"><img class="logo-light" alt="TÜV TRUST IT" src="'+r+'" loading="lazy"><img class="logo-dark" alt="TÜV TRUST IT" src="'+a+'" loading="lazy"></a><a class="partner-card" href="https://www.wu.ac.at/" target="_blank" rel="noreferrer"><img class="logo-light" alt="WU Wien" src="'+n+'" loading="lazy"><img class="logo-dark" alt="WU Wien" src="'+t+'" loading="lazy"></a><a class="partner-card" href="https://www.ikarussecurity.com/" target="_blank" rel="noreferrer"><img alt="IKARUS Security" src="'+i+'" loading="lazy"></a><a class="partner-card" href="https://www.roteskreuz.at/niederoesterreich/home" target="_blank" rel="noreferrer"><img alt="Red Cross Lower Austria" src="'+s+'" loading="lazy"></a><a class="partner-card" href="https://www.vbv.at/" target="_blank" rel="noreferrer"><img alt="VBV-Gruppe" src="'+o+'" loading="lazy"></a></div><div class="cta-row"><a class="md-button" href="/de/pentesting-demo-reports"><span class="iconify" data-icon="mdi:file-document" aria-hidden="true"></span> Zu unseren Demo-Berichten</a></div><h2 id="unsere-starken" tabindex="-1">Unsere Stärken <a class="header-anchor" href="#unsere-starken" aria-label="Permalink to &quot;Unsere Stärken&quot;">​</a></h2><h3 id="klarer-fokus" tabindex="-1">Klarer Fokus <a class="header-anchor" href="#klarer-fokus" aria-label="Permalink to &quot;Klarer Fokus&quot;">​</a></h3><p>Unsere Schwerpunkte liegen auf Windows Active Directory- und Entra-ID-Infrastrukturen, sowie Web-Applikationen. Damit garantieren wir euch die höchste Qualität und die effizienteste Arbeit.</p><h3 id="großtes-know-how" tabindex="-1">Größtes Know-How <a class="header-anchor" href="#großtes-know-how" aria-label="Permalink to &quot;Größtes Know-How&quot;">​</a></h3><p>Unsere Fachkompetenz ist das Ergebnis einer soliden Ausbildung im Bereich IT-Security, langjähriger Erfahrung im Bereich Penetration-Testing und der Zusammenarbeit sowie dem Austausch mit den besten Security-Talenten Europas.</p><h3 id="starkes-team" tabindex="-1">Starkes Team <a class="header-anchor" href="#starkes-team" aria-label="Permalink to &quot;Starkes Team&quot;">​</a></h3><p>Wir sind vier Persönlichkeiten und ein Team! Wir Gründer verfügen über Erfahrung und Expertise im Security-Feld unterschiedlicher Branchen, wie Industrie, Banken und Finanzen, Glücksspiel und Online-Casino sowie der Automobil-Branche.</p><h3 id="nachhaltige-kooperation" tabindex="-1">Nachhaltige Kooperation <a class="header-anchor" href="#nachhaltige-kooperation" aria-label="Permalink to &quot;Nachhaltige Kooperation&quot;">​</a></h3><p>Wir setzen auf Handschlagqualität, Kooperation und persönlichen Kontakt. Wir möchten Security in Organisationen nachhaltig verbessern und legen daher Wert auf langfristige Partnerschaften mit unseren Kunden.</p><br><div class="cta-row" style="text-align:center;"><a class="md-button" href="/de/contact-us" style="text-align:center;"><span class="iconify" data-icon="mdi:email-edit" aria-hidden="true"></span> Zu unseren Kontaktdaten</a></div><br>',19)])])}const S=l(h,[["render",m]]);export{y as __pageData,S as default};
